 62→class PrepublishingBottomSheetFragment : WPBottomSheetDialogFragment(),
 63→    PrepublishingScreenClosedListener, PrepublishingActionClickedListener, PrepublishingSocialViewModelProvider {
 64→    @Inject
 65→    internal lateinit var viewModelFactory: ViewModelProvider.Factory
 66→
 67→    @Inject
 68→    internal lateinit var analyticsTrackerWrapper: AnalyticsTrackerWrapper
 69→    private lateinit var viewModel: PrepublishingViewModel
 70→    private lateinit var keyboardResizeViewUtil: KeyboardResizeViewUtil
 71→
 72→    private var prepublishingBottomSheetListener: PrepublishingBottomSheetListener? = null
 73→
 74→    private var jetpackSocialViewModel: EditorJetpackSocialViewModel? = null
 75→    private lateinit var editShareMessageActivityResultLauncher: ActivityResultLauncher<Intent>
 76→
 77→    override fun onCreate(savedInstanceState: Bundle?) {
 78→        super.onCreate(savedInstanceState)
 79→        (requireNotNull(activity).application as WordPress).component().inject(this)
 80→    }
 81→
 82→    override fun onAttach(context: Context) {
 83→        super.onAttach(context)
 84→        prepublishingBottomSheetListener = if (context is PrepublishingBottomSheetListener) {
 85→            context
 86→        } else {
 87→            throw RuntimeException("$context must implement PrepublishingBottomSheetListener")
 88→        }
 89→
 90→        editShareMessageActivityResultLauncher = registerForActivityResult(
 91→            ActivityResultContracts.StartActivityForResult()
 92→        ) { result ->
 93→            if (result.resultCode == Activity.RESULT_OK) {
 94→                result.data?.let {
 95→                    val shareMessage = it.getStringExtra(
 96→                        EditJetpackSocialShareMessageActivity.RESULT_UPDATED_SHARE_MESSAGE
 97→                    )
 98→                    getEditorJetpackSocialViewModel().onJetpackSocialShareMessageChanged(shareMessage)
 99→                }
100→            }
101→        }
102→    }
103→
104→    override fun onDetach() {
105→        super.onDetach()
106→        prepublishingBottomSheetListener = null
107→    }
108→
109→    override fun onCreateView(
110→        inflater: LayoutInflater,
111→        container: ViewGroup?,
112→        savedInstanceState: Bundle?
113→    ): View? {
114→        val view = inflater.inflate(R.layout.post_prepublishing_bottom_sheet, container)
115→        keyboardResizeViewUtil = KeyboardResizeViewUtil(requireActivity(), view)
116→        keyboardResizeViewUtil.enable()
117→        return view
118→    }
119→
120→    override fun onResume() {
121→        super.onResume()
122→        getEditorJetpackSocialViewModel().onResume(JetpackSocialFlow.PRE_PUBLISHING)
123→        /**
124→         * The back button normally closes the bottom sheet so now instead of doing that it goes back to
125→         * the home screen with the actions and only if pressed again will it close the bottom sheet.
126→         */
127→        dialog?.setOnKeyListener { _, keyCode, event ->
128→            if (keyCode == KeyEvent.KEYCODE_BACK) {
129→                if (event.action != KeyEvent.ACTION_DOWN) {
130→                    true
131→                } else {
132→                    viewModel.onDeviceBackPressed()
133→                    true
134→                }
135→            } else {
136→                false
137→            }
138→        }
139→    }
140→
141→    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
142→        super.onViewCreated(view, savedInstanceState)
143→        with(PostPrepublishingBottomSheetBinding.bind(view)) {
144→            initViewModel(savedInstanceState)
145→            dialog?.setOnShowListener { dialogInterface ->
146→                val sheetDialog = dialogInterface as? BottomSheetDialog
147→
148→                val bottomSheet = sheetDialog?.findViewById<View>(
149→                    MaterialR.id.design_bottom_sheet
150→                ) as? FrameLayout
151→
152→                bottomSheet?.let {
153→                    val behavior = BottomSheetBehavior.from(it)
154→                    behavior.state = BottomSheetBehavior.STATE_EXPANDED
155→                    behavior.skipCollapsed = true
156→                }
157→            }
158→            setupMinimumHeightForFragmentContainer()
159→        }
160→    }
161→
162→    override fun onDismiss(dialog: DialogInterface) {
163→        analyticsTrackerWrapper.track(Stat.PREPUBLISHING_BOTTOM_SHEET_DISMISSED)
164→        super.onDismiss(dialog)
165→    }
