102→    SAVE_AS_DRAFT(R.string.menu_save_as_draft, isVisible = true),
103→    SAVE(R.string.save, isVisible = true),
104→    PUBLISH_NOW(R.string.menu_publish_now, isVisible = true),
105→    NONE(titleResource = null, isVisible = false);
106→}
