 10→
 11→@Reusable
 12→class EditorActionsProvider @Inject constructor() {
 13→    @JvmOverloads
 14→    fun getPrimaryAction(
 15→        postStatus: PostStatus,
 16→        userCanPublish: Boolean,
 17→        isLandingEditor: Boolean = false
 18→    ): PrimaryEditorAction {
 19→        return if (userCanPublish) {
 20→            when (postStatus) {
 21→                PostStatus.SCHEDULED -> PrimaryEditorAction.SCHEDULE
 22→                PostStatus.DRAFT -> PrimaryEditorAction.PUBLISH_NOW
 23→                PostStatus.PENDING, PostStatus.TRASHED -> PrimaryEditorAction.SAVE
 24→                PostStatus.PUBLISHED ->
 25→                    if (isLandingEditor) PrimaryEditorAction.CONTINUE else PrimaryEditorAction.UPDATE
 26→                PostStatus.PRIVATE, PostStatus.UNKNOWN -> PrimaryEditorAction.UPDATE
 27→            }
 28→        } else {
 29→            // User doesn't have publishing permissions
 30→            when (postStatus) {
 31→                PostStatus.DRAFT,
 32→                PostStatus.PENDING,
 33→                PostStatus.UNKNOWN -> PrimaryEditorAction.SUBMIT_FOR_REVIEW
 34→                PostStatus.TRASHED -> {
 35→                    AppLog.e(
 36→                        T.EDITOR, "User shouldn't be able to open a trashed post in an editor " +
 37→                                "without publishing rights."
 38→                    )
 39→                    PrimaryEditorAction.SAVE
 40→                }
 41→                PostStatus.PUBLISHED,
 42→                PostStatus.SCHEDULED,
 43→                PostStatus.PRIVATE -> {
 44→                    AppLog.e(
 45→                        T.EDITOR, "User shouldn't be able to open a public ($postStatus) post in an editor " +
 46→                                "without publishing rights."
 47→                    )
 48→                    PrimaryEditorAction.SUBMIT_FOR_REVIEW
 49→                }
 50→            }
 51→        }
 52→    }
 53→
 54→    fun getSecondaryAction(
 55→        postStatus: PostStatus,
 56→        userCanPublish: Boolean
 57→    ): SecondaryEditorAction {
 58→        return if (userCanPublish) {
 59→            when (postStatus) {
 60→                PostStatus.DRAFT -> SecondaryEditorAction.SAVE
 61→                PostStatus.PENDING, PostStatus.SCHEDULED -> SecondaryEditorAction.PUBLISH_NOW
 62→                PostStatus.PRIVATE, PostStatus.PUBLISHED -> SecondaryEditorAction.NONE
 63→                PostStatus.TRASHED, PostStatus.UNKNOWN -> SecondaryEditorAction.SAVE_AS_DRAFT
 64→            }
 65→        } else {
 66→            // User doesn't have publishing permissions
 67→            when (postStatus) {
 68→                PostStatus.DRAFT,
 69→                PostStatus.PENDING,
 70→                PostStatus.UNKNOWN -> SecondaryEditorAction.NONE
 71→                PostStatus.TRASHED -> {
 72→                    AppLog.e(
 73→                        T.EDITOR, "User shouldn't be able to open a trashed post in an editor " +
 74→                                "without publishing rights."
 75→                    )
 76→                    SecondaryEditorAction.SAVE_AS_DRAFT
 77→                }
 78→                PostStatus.PUBLISHED,
 79→                PostStatus.SCHEDULED,
 80→                PostStatus.PRIVATE -> {
 81→                    AppLog.e(
 82→                        T.EDITOR, "User shouldn't be able to open a public ($postStatus) post in an editor " +
 83→                                "without publishing rights."
 84→                    )
 85→                    SecondaryEditorAction.NONE
 86→                }
 87→            }
 88→        }
 89→    }
 90→}
