 92→enum class PrimaryEditorAction(@StringRes val titleResource: Int) {
 93→    SUBMIT_FOR_REVIEW(R.string.submit_for_review),
 94→    PUBLISH_NOW(R.string.button_publish),
 95→    SCHEDULE(R.string.schedule_verb),
 96→    UPDATE(R.string.update_verb),
 97→    CONTINUE(R.string.continue_label),
 98→    SAVE(R.string.save);
 99→}
